public class Solution {
    public static long solve(long n, long[][] edges, long k) {
        // Sort edges by weight
        Arrays.sort(edges, (a, b) -> Long.compare(a[2], b[2]));
        long maxWeight = 0;
        for (long[] edge : edges) {
            maxWeight = Math.max(maxWeight, edge[2]);
        }
        long low = 0, high = maxWeight;
        long answer = maxWeight;
        while (low <= high) {
            long mid = (low + high) / 2;
            DSU dsu = new DSU((int) n);
            for (long[] edge : edges) {
                if (edge[2] <= mid) {
                    dsu.union((int) edge[0], (int) edge[1]);
                }
            }
            int components = dsu.countComponents();
            if (components <= k) {
                answer = mid;
                high = mid - 1;
            } else {
                low = mid + 1;
            }
        }
        return answer;
    }

    private static class DSU {
        private int[] parent;
        private int[] rank;

        public DSU(int n) {
            parent = new int[n];
            rank = new int[n];
            for (int i = 0; i < n; i++) {
                parent[i] = i;
                rank[i] = 1;
            }
        }

        public int find(int x) {
            if (parent[x] != x) {
                parent[x] = find(parent[x]);
            }
            return parent[x];
        }

        public boolean union(int x, int y) {
            int rootX = find(x);
            int rootY = find(y);
            if (rootX == rootY) {
                return false;
            }
            if (rank[rootX] < rank[rootY]) {
                parent[rootX] = rootY;
            } else {
                parent[rootY] = rootX;
                if (rank[rootX] == rank[rootY]) {
                    rank[rootX]++;
                }
            }
            return true;
        }

        public int countComponents() {
            Set<Integer> roots = new HashSet<>();
            for (int i = 0; i < parent.length; i++) {
                roots.add(find(i));
            }
            return roots.size();
        }
    }
}

