public class Solution {
    public static long solve(long n, long[][] edges, long k) {
        if (n == 1) return 0;
        Arrays.sort(edges, (a, b) -> Long.compare(a[2], b[2]));
        long maxWeight = edges[edges.length - 1][2];
        long low = 0, high = maxWeight;
        long answer = maxWeight;
        while (low <= high) {
            long mid = (low + high) / 2;
            DSU dsu = new DSU(n);
            for (long[] edge : edges) {
                if (edge[2] <= mid) {
                    dsu.union(edge[0], edge[1]);
                }
            }
            long components = dsu.countComponents();
            if (components <= k) {
                answer = mid;
                high = mid - 1;
            } else {
                low = mid + 1;
            }
        }
        return answer;
    }

    static class DSU {
        private long n;
        private long[] parent;
        private long[] rank;

        public DSU(long n) {
            this.n = n;
            parent = new long[(int) n];
            rank = new long[(int) n];
            for (long i = 0; i < n; i++) {
                parent[i] = i;
                rank[i] = 0;
            }
        }

        public long find(long u) {
            if (parent[u] != u) {
                parent[u] = find(parent[u]);
            }
            return parent[u];
        }

        public boolean union(long u, long v) {
            long rootU = find(u);
            long rootV = find(v);
            if (rootU == rootV) return false;
            if (rank[rootU] < rank[rootV]) {
                parent[rootU] = rootV;
            } else {
                parent[rootV] = rootU;
                if (rank[rootU] == rank[rootV]) {
                    rank[rootU]++;
                }
            }
            return true;
        }

        public long countComponents() {
            Set<Long> roots = new HashSet<>();
            for (long i = 0; i < n; i++) {
                roots.add(find(i));
            }
            return roots.size();
        }
    }
}
